%[text] # `Figure 1: Cartoon`
%[text] `Figure 1 in the manuscript used "Pseudorandom.Seed = 9;" during data generation.`
%[text] `See "Figure2.m" for Data Generation Code.`
%%
%[text] ## `Configure MATLAB:`
restoredefaultpath;    clear;    close all;    clc;    addpath(genpath(fileparts(mfilename('fullpath')))) % In case "Configure" is not available.
Configure
%%
load("Data(Figure=1).mat")
StairWidth  =  1    ;
Color.Black = [0 0 0]; %[control:colorPicker:2273]{"position":[15,22]}
Color.Gray  = [0.278 0.278 0.278]; %[control:colorPicker:3b09]{"position":[15,34]}
Color.Path  = [0.502 0.502 0.502]; %[control:colorPicker:9314]{"position":[15,34]}
StairStyle  = "-"   ;
Color.Long  = [0.067 0.443 0.745]; %[control:colorPicker:73a4]{"position":[15,34]}
Color.Rest  = [0.867 0.329 0.000]; %[control:colorPicker:03e3]{"position":[15,34]}
Color.Many  = [0.867 0.329 0.000]; %[control:colorPicker:66bb]{"position":[15,34]}
Color.Prior = [0.929 0.694 0.125]; %[control:colorPicker:84ad]{"position":[15,34]}
Color.True  = [0.231 0.667 0.196]; %[control:colorPicker:2ce3]{"position":[15,34]}
LineWidth   =  2.2 ;
FontTitle   = 20   ;
FontMain    = 16   ;
FontBig     = 26   ;
FontMid     = 14   ;
SigDigs     =  2   ;
FontSize    = 16   ;

Showing = nSegments;

% YLim shared across all traces:
allMany = cell2mat(cellfun(@(x) x(:), Many.w(:), 'UniformOutput', false));
yMin = min([Long.w(:); allMany(:)]);
yMax = max([Long.w(:); allMany(:)]);
yPad = 0.10 * (yMax - yMin);
yLim = [yMin - yPad, yMax + yPad];
%[text] ###  `Initialize:`
Figure = figure('Color','w', "Position",[80 80 1500 820]); %[output:1b012c90]
%Tiles  = tiledlayout(Figure, 3, 12, 'TileSpacing','compact', 'Padding','compact');
Tiles  = tiledlayout(Figure, 2, 10, 'TileSpacing','Compact', 'Padding','Compact'); %[output:1b012c90]
boxY   = [0.35    0.60];
%[text] ###  `Long Trajectory` $(\\mathbf{\\mathit{w}})$`:`
axLong = nexttile(Tiles, [1 5]); %[output:1b012c90]
axLong.FontSize = FontSize; %[output:1b012c90]

hold(axLong, "On") %[output:1b012c90]
axLong.Box = "On"; %[output:1b012c90]

scatter(axLong, 1:Long.nTimes, Long.w,  "LineWidth", LineWidth, "SizeData",5, "MarkerFaceColor",Color.Long, "MarkerEdgeColor",Color.Long, "DisplayName",'Measurement') %[output:1b012c90]
stairs(axLong, 1:Long.nTimes, Long.S, "Color", Color.Path, "LineWidth",StairWidth, "DisplayName",'GT Path', "LineStyle",StairStyle); %[output:1b012c90]

ylim(axLong, yLim) %[output:1b012c90]
xlim(axLong, [1 Long.nTimes]) %[output:1b012c90]

axLong.XTick = linspace(axLong.XLim(1), axLong.XLim(2), 5); %[output:1b012c90]
xticklabels(axLong, {"$t_{0}$", "", "$t$: Time [s]", "", "$t_{N}$"}) %[output:1b012c90]


axLong.YTick = GT.Mean; %[output:1b012c90]
yticklabels(axLong, ["$\sigma_{1}$"  "$\sigma_{2}$"]) %[output:1b012c90]
axLong.YAxis.TickLabelColor    = Color.Long; %[output:1b012c90]

axLong.Title.String = "$\mathbf{\mathit{w}}=w_{1:N}$"; %[output:1b012c90]
axLong.Title.Color  = Color.Long; %[output:1b012c90]

text(axLong, 0.50, -0.25, "$\Longrightarrow$" , "Rotation",270, "Units",'Normalized', "FontSize",FontSize+6, "Color",Color.Long, "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]
text(axLong, 0.42, -0.35, "$\mathrm{TransitionMatrix}_{\mathbf{\mathit{w}}} \equiv \left(\begin{array}{cc} 1-\widehat{\pi}_{\sigma_{1}\to\sigma_{2}} & \widehat{\pi}_{\sigma_{1}\to\sigma_{2}} \\ \widehat{\pi}_{\sigma_{2}\to\sigma_{1}} & 1-\widehat{\pi}_{\sigma_{2}\to\sigma_{1}} \end{array}\right)$", "Rotation",  0, "Units",'Normalized', ... %[output:1b012c90]
                         "FontSize",FontSize+4, "Color",Color.Long, "HorizontalAlignment",'Center', "VerticalAlignment",'Top') %[output:1b012c90]

Legend = legend(axLong); %[output:1b012c90]
Legend.Orientation = "Horizontal"; %[output:1b012c90]
Legend.Box = "Off"; %[output:1b012c90]
%[text] ## `Segmented Trajectories` $(\\widetilde{\\mathbf{w}})$`:`
axRest = nexttile(Tiles, [1 5]); %[output:1b012c90]
axRest.FontSize = FontSize; %[output:1b012c90]

hold(axRest, "On") %[output:1b012c90]
axRest.Box = "On"; %[output:1b012c90]




for Index = 1 : length(startSegment)
    Times = startSegment(Index) : endSegment(Index);
    stairs(axRest, Times, Long.S(Times), "Color", Color.Path, "LineWidth",StairWidth, "DisplayName",'GT', "LineStyle",StairStyle); %[output:1b012c90]
end

scatter(axRest, 1:Long.nTimes, Long.w,  "LineWidth", LineWidth, "SizeData",5, "MarkerFaceColor",Color.Rest, "MarkerEdgeColor",Color.Rest) %[output:1b012c90]
ylim(axRest, yLim) %[output:1b012c90]
xlim(axRest, [1 Long.nTimes]) %[output:1b012c90]

axRest.XTick = linspace(axRest.XLim(1), axRest.XLim(2), 3); %[output:1b012c90]
axRest.XTick = linspace(axRest.XLim(1), axRest.XLim(2), 5); %[output:1b012c90]
xticklabels(axRest, {"$t_{0}$", "$\uparrow$", "Time", "$\uparrow$", "$t_{N}$"}) %[output:1b012c90]

axRest.YTick = GT.Mean; %[output:1b012c90]
yticklabels(axRest, {}) %[output:1b012c90]
axRest.YAxis.TickLabelRotation = 90        ; %[output:1b012c90]
axRest.YAxis.TickLabelColor    = Color.Rest; %[output:1b012c90]

axRest.Title.String   = "$\widetilde{\mathbf{w}}$"; %[output:1b012c90]
axRest.Title.Color    = Color.Rest; %[output:1b012c90]
axRest.Title.FontSize = FontSize+4; %[output:1b012c90]


text(axRest, 0.5, -0.25 , "$\Longrightarrow$" , "Rotation",270, "Units",'Normalized', "FontSize",FontSize+6, "Color",Color.Rest, "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]
text(axRest, 0.5, -0.475, "$\mathrm{TransitionMatrix}_{\widetilde{\mathbf{w}}}$", "Rotation",  0, "Units",'Normalized', "FontSize",FontSize+4, "Color",Color.Rest, "HorizontalAlignment",'Center', "VerticalAlignment",'Top') %[output:1b012c90]


text(axRest, -0.45, -0.15, '$?$', "Color",Color.Black, "FontSize",FontSize+4, "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]
text(axRest, -0.45, -0.25, '$=$', "Color",Color.Black, "FontSize",FontSize+8, "FontWeight",'Bold', "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]


%{
% Numbers:
text(axLong, 0.5, -0.95, "$I_{\widetilde{\mathbf{\mathit{w}}}} \equiv \langle{\log_{2}\mathrm{\frac{Posterior}{Prior}}}\rangle_{\mathrm{Posterior}}=" + round(Info.Long.bits,SigDigs)        + "\, \mathrm{bits}$", "Interpreter",'LaTeX', "FontSize",FontSize+4, "HorizontalAlignment",'Center', "Units",'Normalized')
text(axRest, 0.5, -0.95, "$I_{\widetilde{\mathbf{w}}}="          + round(Info.LongRestart.bits,SigDigs) + "\, \mathrm{bits}$", "Interpreter",'LaTeX', "FontSize",FontSize+4, "HorizontalAlignment",'Center', "Units",'Normalized')
text(axMany, 0.5, -0.95, "$I_{\mathbf{u}}=" + round(Info.Many.bits,SigDigs) + "\, \mathrm{bits}$", "Interpreter",'LaTeX', "FontSize",FontTitle, "HorizontalAlignment",'Center', "Units",'Normalized')
%}
% No Numbers:
text(axLong, 0.5, -0.985, "$\mathrm{Information}_{{\mathbf{\mathit{w}}}} \equiv \left\langle{\log_{2}\!\,\mathrm{\frac{Posterior(\widehat{\mathbf{\Pi}}\,|\,{\mathbf{\mathit{w}}})}{Prior}}}\right\rangle_{\!\!\!\mathrm{Posterior}}$", "Interpreter",'LaTeX', "FontSize",FontSize+4, "HorizontalAlignment",'Center', "Units",'Normalized', "Color",Color.Long) %[output:1b012c90]
text(axRest, 0.5, -0.985, "$\mathrm{Information}_{\widetilde{\mathbf{w}}}$", "Interpreter",'LaTeX', "FontSize",FontSize+4, "HorizontalAlignment",'Center', "Units",'Normalized', "Color",Color.Rest) %[output:1b012c90]

text(axRest, -0.45, -0.765, '$?$', "Color",Color.Black, "FontSize",FontSize+4, "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]
text(axRest, -0.45, -0.865, '$=$', "Color",Color.Black, "FontSize",FontSize+8, "FontWeight",'Bold', "HorizontalAlignment",'Center', "VerticalAlignment",'Middle') %[output:1b012c90]

%{
if~exist("Leg0",'var');    Leg0 = Legend.Position;    end
Legend.Position = Leg0 + [-0.455,-0.051  ,  +0.375/10,0];
%}

text(axLong, axLong.Title.Position(1)*1.95,axLong.Title.Position(2)*1.0525, "$\to$", "FontSize",FontSize+12) %[output:1b012c90]
%%
print("Figure(Cartoon)","-dpng","-r350")
exportgraphics(Figure, "Figure(Cartoon).svg");
%%
function p = data2norm(Axes, x, y)
    oldUnits   = Axes.Units                          ; 
    Axes.Units = "Normalized"                        ;
    ap         = Axes.Position                       ;
    xr         = (x - Axes.XLim(1)) / diff(Axes.XLim);
    yr         = (y - Axes.YLim(1)) / diff(Axes.YLim);
    p          = [ap(1) + xr*ap(3), ap(2) + yr*ap(4)];
    Axes.Units = oldUnits;
end

